const termo = $('Receber Termo').first().json.termo || '';

// match_produtos já filtra ativo=true no banco (ver migration 20260602120000).
// O filtro abaixo é uma segunda camada de segurança caso o campo ativo venha na resposta.
const lista = $input.all()
  .map(item => item.json)
  .filter(p => p.ativo !== false);

if (lista.length === 0) {
  return [{
    json: {
      resultado: `Nenhum produto disponível encontrado para "${termo}". Tente um nome diferente ou consulte por categoria.`,
      produtos: []
    }
  }];
}

const formatarPreco = (v) =>
  Number(v || 0).toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' });

const linhas = lista.map((p) => {
  // ativo=true garantido pela função SQL; status baseado no estoque
  const temEstoque = Number(p.estoque_atual || p.estoque || 0) > 0;
  const status = temEstoque ? 'disponível' : 'sem estoque';
  const preco = formatarPreco(p.preco_atual || p.preco || 0);
  const unidade = p.unidade || 'un';
  return `- ${p.nome}: ${preco}/${unidade} (${status})`;
});

const nome = $('Receber Termo').first().json.nome_cliente || '';

const gatilhos = [
  nome ? `${nome}, esse produto ta saindo bastante hoje. Quer garantir o seu antes de acabar?` : `Esse produto ta saindo bastante hoje. Quer garantir o seu antes de acabar?`,
  nome ? `${nome}, posso separar agora para voce? E so me dizer a quantidade!` : `Posso separar agora para voce? E so me dizer a quantidade!`,
  nome ? `${nome}, varios clientes que levaram esse aproveitaram para fechar o pedido completo. Quer que eu monte um para voce?` : `Varios clientes que levaram esse aproveitaram para fechar o pedido completo. Quer que eu monte um para voce?`,
  nome ? `${nome}, esse e um dos favoritos aqui da loja. Me fala a quantidade que voce precisa!` : `Esse e um dos favoritos aqui da loja. Me fala a quantidade que voce precisa!`,
  nome ? `${nome}, aproveita que temos em estoque agora. Quantos quilos voce quer separar?` : `Aproveita que temos em estoque agora. Quantos quilos voce quer separar?`,
  nome ? `${nome}, posso deixar separado para voce ainda hoje. Qual a quantidade?` : `Posso deixar separado para voce ainda hoje. Qual a quantidade?`,
  nome ? `${nome}, quem experimenta esse produto sempre volta a pedir. Quer garantir o seu?` : `Quem experimenta esse produto sempre volta a pedir. Quer garantir o seu?`,
  nome ? `${nome}, e so confirmar a quantidade que ja separo para voce!` : `E so confirmar a quantidade que ja separo para voce!`,
  nome ? `${nome}, nossos clientes adoram esse produto. Posso separar uma quantidade para voce?` : `Nossos clientes adoram esse produto. Posso separar uma quantidade para voce?`,
  nome ? `${nome}, nao deixa para depois nao! Me diz quanto voce precisa e eu ja separo.` : `Nao deixa para depois nao! Me diz quanto voce precisa e eu ja separo.`
];

const gatilho = gatilhos[Math.floor(Math.random() * gatilhos.length)];

return [{
  json: {
    resultado: linhas.join('\n') + `\n\n${gatilho}`,
    produtos: lista.map((p) => ({
      produto_id: p.id || '',
      nome: p.nome || '',
      preco_unitario: Number(p.preco_atual || p.preco || 0),
      unidade: p.unidade || 'un',
      estoque: Number(p.estoque_atual || p.estoque || 0)
    }))
  }
}];
